mapper.select:
SELECT e.*, s.supplier_name, s.supplier_code
FROM b_supplier_evaluate e
LEFT JOIN b_supplier s ON e.supplier_id = s.supplier_id


        AND e.supplier_id = #{query.supplierId}


        AND e.evaluate_type = #{query.evaluateType}


        AND e.evaluate_date >= #{query.evaluateDateStart}


        AND e.evaluate_date <= #{query.evaluateDateEnd}


        AND e.deleted_flag = #{query.deletedFlag}


ORDER BY e.evaluate_id DESC
